package com.example.bankingapp;

import android.os.Bundle;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;

public class BankActivity extends AppCompatActivity {

    private double accountBalance = 5000.00; // Sample initial balance
    private TextView balanceTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_bank);
        
        balanceTextView = findViewById(R.id.balanceTextView);
        updateBalanceDisplay();

        processTransaction(1000.00, "credit"); // Sample transaction
    }

    private void processTransaction(double amount, String transactionType) {
        if (transactionType.equals("credit")) {
            accountBalance += amount;
        } else if (transactionType.equals("debit") && accountBalance >= amount) {
            accountBalance -= amount;
        }
        updateBalanceDisplay();
    }

    private void updateBalanceDisplay() {
        balanceTextView.setText("Balance: $ " + String.format("%.2f", accountBalance));
    }
}

